-- ── manager → SUPERVISEUR ────────────────────────────────────────────────── IF NOT EXISTS (SELECT 1 FROM Utilisateur WHERE LOWER(LTRIM(RTRIM(login))) = N'manager') BEGIN INSERT INTO Utilisateur (login, mot_de_passe_hash, nom_complet, email, telephone, actif, nombre_echecs, version, code_agence) VALUES (N'manager', N'$2b$12$qQcLK3GrGfDTsfJROQn5JuyEsj7re6AR3WKldnwvILxQf9eWXcCsi', N'Manager Général', N'manager@microfina.com', N'22260301', 1, 0, 0, N'NKC'); END;
INSERT INTO UtilisateurRole (id_utilisateur, id_role) SELECT u.id, r.id FROM Utilisateur u CROSS JOIN Role r WHERE LOWER(LTRIM(RTRIM(u.login))) = N'manager' AND r.code_role = N'SUPERVISEUR' AND NOT EXISTS (SELECT 1 FROM UtilisateurRole ur WHERE ur.id_utilisateur = u.id AND ur.id_role = r.id);
